  1→import { Transition } from '@headlessui/react';
  2→import { InertiaLinkProps, Link } from '@inertiajs/react';
  3→import {
  4→    createContext,
  5→    Dispatch,
  6→    PropsWithChildren,
  7→    SetStateAction,
  8→    useContext,
  9→    useState,
 10→} from 'react';
 11→
 12→const DropDownContext = createContext<{
 13→    open: boolean;
 14→    setOpen: Dispatch<SetStateAction<boolean>>;
 15→    toggleOpen: () => void;
 16→}>({
 17→    open: false,
 18→    setOpen: () => {},
 19→    toggleOpen: () => {},
 20→});
 21→
 22→const Dropdown = ({ children }: PropsWithChildren) => {
 23→    const [open, setOpen] = useState(false);
 24→
 25→    const toggleOpen = () => {
 26→        setOpen((previousState) => !previousState);
 27→    };
 28→
 29→    return (
 30→        <DropDownContext.Provider value={{ open, setOpen, toggleOpen }}>
 31→            <div className="relative">{children}</div>
 32→        </DropDownContext.Provider>
 33→    );
 34→};
 35→
 36→const Trigger = ({ children }: PropsWithChildren) => {
 37→    const { open, setOpen, toggleOpen } = useContext(DropDownContext);
 38→
 39→    return (
 40→        <>
 41→            <div onClick={toggleOpen}>{children}</div>
 42→
 43→            {open && (
 44→                <div
 45→                    className="fixed inset-0 z-40"
 46→                    onClick={() => setOpen(false)}
 47→                ></div>
 48→            )}
 49→        </>
 50→    );
 51→};
 52→
 53→const Content = ({
 54→    align = 'right',
 55→    width = '48',
 56→    contentClasses = 'py-1 bg-white',
 57→    children,
 58→}: PropsWithChildren<{
 59→    align?: 'left' | 'right';
 60→    width?: '48';
 61→    contentClasses?: string;
 62→}>) => {
 63→    const { open, setOpen } = useContext(DropDownContext);
 64→
 65→    let alignmentClasses = 'origin-top';
 66→
 67→    if (align === 'left') {
 68→        alignmentClasses = 'ltr:origin-top-left rtl:origin-top-right start-0';
 69→    } else if (align === 'right') {
 70→        alignmentClasses = 'ltr:origin-top-right rtl:origin-top-left end-0';
 71→    }
 72→
 73→    let widthClasses = '';
 74→
 75→    if (width === '48') {
 76→        widthClasses = 'w-48';
 77→    }
 78→
 79→    return (
 80→        <>
 81→            <Transition
 82→                show={open}
 83→                enter="transition ease-out duration-200"
 84→                enterFrom="opacity-0 scale-95"
 85→                enterTo="opacity-100 scale-100"
 86→                leave="transition ease-in duration-75"
 87→                leaveFrom="opacity-100 scale-100"
 88→                leaveTo="opacity-0 scale-95"
 89→            >
 90→                <div
 91→                    className={`absolute z-50 mt-2 rounded-md shadow-lg ${alignmentClasses} ${widthClasses}`}
 92→                    onClick={() => setOpen(false)}
 93→                >
 94→                    <div
 95→                        className={
 96→                            `rounded-md ring-1 ring-black ring-opacity-5 ` +
 97→                            contentClasses
 98→                        }
 99→                    >
100→                        {children}
101→                    </div>
102→                </div>
103→            </Transition>
104→        </>
105→    );
106→};
107→
108→const DropdownLink = ({
109→    className = '',
110→    children,
111→    ...props
112→}: InertiaLinkProps) => {
113→    return (
114→        <Link
115→            {...props}
116→            className={
117→                'block w-full px-4 py-2 text-start text-sm leading-5 text-gray-700 transition duration-150 ease-in-out hover:bg-gray-100 focus:bg-gray-100 focus:outline-none ' +
118→                className
119→            }
120→        >
121→            {children}
122→        </Link>
123→    );
124→};
125→
126→Dropdown.Trigger = Trigger;
127→Dropdown.Content = Content;
128→Dropdown.Link = DropdownLink;
129→
130→export default Dropdown;
